import React, { useState } from 'react';

interface Props {
    name: string;
    showAge?: boolean;
}

const Greeting: React.FC<Props> = ({ name, showAge = false }) => {
    const [age, setAge] = useState<number>(0);

    return (
        <div>
            <div>Hello, {name}!</div>
            {showAge && <div>Age: {age}</div>}
        </div>
    );
};
